'use strict';

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function backoffMs(attempt, baseMs = 200, maxMs = 2000) {
  const ms = baseMs * (2 ** (attempt - 1));
  return Math.min(ms, maxMs);
}

console.log(backoffMs(1)); // 200
console.log(backoffMs(2)); // 400
console.log(backoffMs(3)); // 800

async function requestJson(url, options = {}, timeoutMs = 8000) {
  // versão compacta: igual à Parte 3 (status + parse)
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const res = await fetch(url, { ...options, signal: controller.signal });
    const text = await res.text().catch(() => '');

    if (!res.ok) {
      return { ok: false, status: res.status, msg: text || res.statusText };
    }

    try {
      return { ok: true, status: res.status, data: JSON.parse(text) };
    } catch {
      return { ok: false, status: res.status, msg: 'JSON inválido', raw: text };
    }
  } catch (e) {
    if (e && e.name === 'AbortError') return { ok: false, msg: 'timeout/cancelado' };
    return { ok: false, msg: 'erro de rede' };
  } finally {
    clearTimeout(id);
  }
}

function isRetryable(result) {
  if (result.ok) return false;
  // erro de rede/timeout sem status
  if (result.status === undefined) return true;
  return [429, 502, 503, 504].includes(result.status);
}

async function requestWithRetry(url, options = {}, cfg = {}) {
  const retries = cfg.retries ?? 2;
  const baseMs = cfg.baseMs ?? 200;
  const maxMs = cfg.maxMs ?? 2000;
  const timeoutMs = cfg.timeoutMs ?? 8000;

  for (let attempt = 1; attempt <= retries + 1; attempt++) {
    const r = await requestJson(url, options, timeoutMs);
    if (r.ok) return r;

    const retryable = isRetryable(r);
    if (!retryable) return r;

    if (attempt <= retries) {
      const wait = backoffMs(attempt, baseMs, maxMs);
      await sleep(wait);
      continue;
    }

    return r;
  }

  return { ok: false, msg: 'falha inesperada' };
}

// Exemplo conceitual: o servidor precisa suportar
async function criarPedido(pedido) {
  const key = crypto.randomUUID();

  return requestWithRetry('/api/pedidos', {
    method: 'POST',
    headers: {
      'Accept': 'application/json',
      'Content-Type': 'application/json',
      'Idempotency-Key': key,
    },
    body: JSON.stringify(pedido),
  }, { retries: 1, timeoutMs: 8000 });
}

